  _typographyPicker(){ const current=this._value("font_preset","theme_default"); return `<div class="field"><span>${this._t("typography_style")}</span><div class="type-grid" role="radiogroup">${Object.entries(SFC_FONT_PRESETS).map(([key,p])=>{ const theme=SFC_THEMES[this._value("theme","mechanical_gold")]||SFC_THEMES.mechanical_gold; const family=key==="theme_default"?theme.font_family:(p.family||theme.font_family); const weight=key==="theme_default"?theme.font_weight:(p.weight||theme.font_weight); return `<button type="button" class="type-choice ${current===key?"selected":""}" data-font-preset="${this._escape(key)}" role="radio" aria-checked="${current===key?"true":"false"}"><span class="type-name">${this._escape(p.label)}</span><span class="type-desc">${this._escape(p.desc[this._lang()]||p.desc.en)}</span><span class="type-sample" style="font-family:${this._escape(family)};font-weight:${weight}">${this._escape(p.sample)}</span></button>`; }).join("")}</div></div>`; }
